// Extract token IDs from markets for price history lookup
const marketsRaw = $input.first().json;
const markets = Array.isArray(marketsRaw) ? marketsRaw : [marketsRaw];

const results = [];
for (const market of markets) {
  try {
    const clobTokenIds = JSON.parse(market.clobTokenIds || '[]');
    const outcomePrices = JSON.parse(market.outcomePrices || '[]');
    if (clobTokenIds.length > 0 && clobTokenIds[0]) {
      results.push({
        json: {
          conditionId: market.conditionId,
          question: market.question,
          tokenId: clobTokenIds[0],
          currentPrice: parseFloat(outcomePrices[0]) || 0,
          volume: market.volume
        }
      });
    }
  } catch (e) {
    // Skip markets with malformed data
  }
}

return results;

// Merge price history API response with original market data from Extract Token IDs.
// The HTTP Request node overwrites item.json with the price history response,
// so we recover market fields by referencing the prior Code node's output.
const marketItems = $('Extract Token IDs').all();
const results = [];

for (let i = 0; i < $input.all().length; i++) {
  const priceHistory = $input.all()[i].json;
  const market = marketItems[i] ? marketItems[i].json : {};
  results.push({
    json: {
      ...priceHistory,
      _market: market
    }
  });
}

return results;

// Calculate price movement and filter for >10% moves
const WEBHOOK_URL = $env.WEBHOOK_URL || 'http://localhost:3000';
const THRESHOLD = 0.10; // 10%

const results = [];

for (const item of $input.all()) {
  const market = item.json._market || {};
  const history = item.json.history || item.json;
  const prices = Array.isArray(history) ? history : [];

  if (prices.length < 2) continue;

  // Get the oldest and newest price points
  const oldPrice = parseFloat(prices[0].p || prices[0].price || '0');
  const newPrice = parseFloat(prices[prices.length - 1].p || prices[prices.length - 1].price || '0');

  if (oldPrice === 0) continue;

  const change = (newPrice - oldPrice) / oldPrice;
  const absChange = Math.abs(change);

  if (absChange >= THRESHOLD) {
    const direction = change > 0 ? 'UP' : 'DOWN';
    const percentStr = (absChange * 100).toFixed(1);

    results.push({
      json: {
        webhookUrl: WEBHOOK_URL + '/api/alert',
        payload: {
          category: 'movers',
          title: `"${market.question || 'Unknown market'}" moved ${direction} ${percentStr}% in the last hour`,
          body: `"${market.question || 'Unknown market'}" moved ${direction} ${percentStr}% in the last hour ($${oldPrice.toFixed(2)} -> $${newPrice.toFixed(2)}).`,
          market: {
            conditionId: market.conditionId || '',
            question: market.question || 'Unknown market',
            tokenId: market.tokenId || '',
            currentPrice: newPrice
          },
          urgent: absChange >= 0.20,
          metadata: {
            oldPrice: oldPrice,
            newPrice: newPrice,
            percentChange: parseFloat(percentStr),
            direction: direction
          }
        }
      }
    });
  }
}

if (results.length === 0) {
  return [];
}

return results;
